     7→import { getPointsExtract, getPointsBalance } from '../../newArch/store/rewardProgram/services';
     8→import {
     9→  PointsExtractStatus,
    10→  PointsBalanceStatus,
    11→  type AppliedFilters,
    12→  type PointsTransaction,
    13→} from '../../newArch/store/rewardProgram/models';
    14→import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
    15→import { EXTRACT_CONSTANTS } from '../../newArch/store/rewardProgram/constants';
    16→import { ANALYTICS_EVENTS, SCREEN_STRINGS } from './data';
    17→import type {
    18→  ExtractRewardProgramProps,
    19→  UseExtractRewardProgramReturn,
    20→  FilterGroup,
    21→} from './Models';
    22→import { PERIOD_DAYS_MAP } from './Models';
    23→import { getFilteredTransactions, getFilteredTransactionsByText, getPlaceholder } from './utils';
    24→import { processPointsExtractData } from '../../newArch/store/rewardProgram/repository';
    25→import useDebounce from '../../hooks/useDebounce';
    26→
    27→const SCROLL_THRESHOLD = 300;
    28→import { useRootStore } from '~/store';
    29→
    30→export function useExtractRewardProgramScreen(
    31→  params?: ExtractRewardProgramProps,
    32→): UseExtractRewardProgramReturn {
    33→  const hasTrackedScreenView = useRef(false);
    34→  const hasTrackedSearchPress = useRef(false);
    35→  const canLoadMoreRef = useRef(false);
    36→  const isLoadingMoreRef = useRef(false);
    37→
    38→  const modalizeRefInfo = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
    39→  const modalizeRefFilters = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
    40→
    41→  const [isRefreshing, setIsRefreshing] = useState(false);
    42→  const [transactionsData, setTransactionsData] = useState<propsItemsListCardTransition[]>([]);
    43→  const [searchText, setSearchText, debouncedSearchText] = useDebounce('', 400);
    44→
    45→  const { pointsExtract, pointsBalance, pointsExtractFilters, pointsExtractActions } =
    46→    useRootStore(
    47→      useShallow((state) => ({
    48→        pointsExtract: state.pointsExtract,
    49→        pointsBalance: state.pointsBalance,
    50→        pointsExtractFilters: state.pointsExtractFilters,
    51→        pointsExtractActions: state.pointsExtractActions,
    52→      })),
    53→    );
    54→
    55→  const isLoadingExtract = pointsExtract.status === PointsExtractStatus.LOADING;
    56→  const isLoadingMore = pointsExtract.isLoadingMore;
    57→  const isLoadingBalance = pointsBalance.status === PointsBalanceStatus.LOADING;
    58→  const appliedTransactionsFilters = pointsExtractFilters.appliedTransactionsFilters;
    59→  const hasError = 
    60→    pointsExtract.status === PointsExtractStatus.ERROR && 
    61→    !isLoadingExtract && 
    62→    (!pointsExtract.extractData || !pointsExtract.extractData.transactions?.length);
    63→
    64→  useFocusEffect(
    65→    useCallback(() => {
    66→      if (!hasTrackedScreenView.current) {
    67→        eventScreenViewV3(
    68→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_name,
    69→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_class,
    70→          ANALYTICS_EVENTS.SCREEN_VIEW.screen_bussines,
    71→          {
    72→            location_1: ANALYTICS_EVENTS.SCREEN_VIEW.location_1,
    73→            location_2: ANALYTICS_EVENTS.SCREEN_VIEW.location_2,
    74→            location_3: ANALYTICS_EVENTS.SCREEN_VIEW.location_3,
    75→          },
    76→        );
    77→        hasTrackedScreenView.current = true;
    78→      }
    79→
    80→      return () => {
    81→        hasTrackedScreenView.current = false;
    82→      };
    83→    }, []),
    84→  );
    85→
    86→  const refreshExtractData = useCallback(() => {
    87→    pointsExtractActions.setExtractStatus(PointsExtractStatus.IDLE);
    88→    pointsExtractActions.setBalanceStatus(PointsBalanceStatus.IDLE);
    89→    pointsExtractActions.setLoadingMore(false);
    90→    getPointsBalance();
    91→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
    92→  }, [pointsExtractActions]);
    93→
    94→  useFocusEffect(
    95→    useCallback(() => {
    96→      refreshExtractData();
    97→    }, [refreshExtractData]),
    98→  );
    99→
   100→  useEffect(() => {
   101→    const shouldFetchBalance =
   102→      pointsBalance.points === undefined ||
   103→      pointsBalance.status === PointsBalanceStatus.ERROR;
   104→
   105→    if (shouldFetchBalance) {
   106→      getPointsBalance();
   107→    }
   108→
   109→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
   110→  }, [pointsBalance.points, pointsBalance.status]);
   111→
   112→  useEffect(() => {
   113→    if (!isLoadingExtract && isRefreshing) {
   114→      setIsRefreshing(false);
   115→    }
   116→  }, [isLoadingExtract, isRefreshing]);
   117→
   118→  useEffect(() => {
   119→    if (searchText.length === 0) {
   120→      hasTrackedSearchPress.current = false;
   121→    }
   122→  }, [searchText]);
   123→
   124→  const getPointsAvailable = useMemo(() => {
   125→    return pointsBalance.points ?? 0;
   126→  }, [pointsBalance.points]);
   127→
   128→  const handleGoBack = useCallback(() => {
   129→    params?.navigation?.goBack();
   130→  }, [params?.navigation]);
   131→
   132→  const requestPointsExtract = useCallback(() => {
   133→    getPointsExtract({ page: EXTRACT_CONSTANTS.DEFAULT_PAGE });
   134→  }, []);
   135→
   136→  const handleLoadMore = useCallback(() => {
   137→    const currentPage = pointsExtract.extractData?.pagination?.page ?? 1;
   138→    const totalPages = pointsExtract.extractData?.pagination?.totalPages ?? 1;
   139→    const canLoadMore = currentPage < totalPages && !pointsExtract.isLoadingMore;
   140→
   141→    if (canLoadMore) {
   142→      getPointsExtract({ page: currentPage + 1 });
   143→    }
   144→  }, [
   145→    pointsExtract.extractData?.pagination,
   146→    pointsExtract.isLoadingMore,
   147→  ]);
   148→
   149→  const setTransactionsFilters = useCallback(
   150→    (filters: AppliedFilters) => {
   151→      pointsExtractActions.setTransactionsFilters(filters);
   152→    },
   153→    [pointsExtractActions],
   154→  );
   155→
   156→  const clearTransactionsFilters = useCallback(() => {
   157→    pointsExtractActions.clearTransactionsFilters();
   158→  }, [pointsExtractActions]);
   159→
   160→  const getTransactionsWithFilters = useCallback(
   161→    (transactions: PointsTransaction[]): PointsTransaction[] => {
   162→      let filtered = transactions;
   163→
   164→      if (appliedTransactionsFilters) {
   165→        const filtersWithDays: AppliedFilters = {
   166→          ...appliedTransactionsFilters,
   167→          period: appliedTransactionsFilters.period !== undefined
   168→            ? PERIOD_DAYS_MAP[appliedTransactionsFilters.period]
   169→            : undefined,
   170→        };
   171→        filtered = getFilteredTransactions(filtered, filtersWithDays);
   172→      }
   173→
   174→      return filtered;
   175→    },
   176→    [appliedTransactionsFilters],
   177→  );
   178→
   179→  const getExtractData = useMemo(() => {
   180→    if (!pointsExtract.extractData) return undefined;
   181→
   182→    const transactions = getTransactionsWithFilters(
   183→      pointsExtract.extractData.transactions,
   184→    );
   185→
   186→    return {
   187→      ...pointsExtract.extractData,
   188→      transactions,
   189→    };
   190→  }, [pointsExtract.extractData, getTransactionsWithFilters]);
   191→
   192→  const getTransactionsData = useMemo(() => {
   193→    if (!getExtractData?.transactions) {
   194→      return [];
   195→    }
   196→
   197→    if (debouncedSearchText && debouncedSearchText.trim() !== '') {
   198→      return getFilteredTransactionsByText(
   199→        getExtractData.transactions,
   200→        debouncedSearchText,
   201→        false,
   202→      );
   203→    }
   204→
   205→    return getExtractData.transactions;
   206→  }, [getExtractData?.transactions, debouncedSearchText]);
   207→
   208→  useEffect(() => {
   209→    if (!getExtractData) return;
   210→
   211→    let cancelled = false;
   212→    const task = InteractionManager.runAfterInteractions(() => {
   213→      if (cancelled) return;
   214→      const processed = processPointsExtractData({
   215→        transactions: getTransactionsData,
   216→        pagination:
   217→          getExtractData.pagination ?? {
   218→            page: 1,
   219→            pageSize: 100,
   220→            total: 0,
   221→            totalPages: 0,
   222→          },
   223→      });
   224→      if (!cancelled) {
   225→        setTransactionsData(processed.mappedTransactions);
   226→      }
   227→    });
   228→
   229→    return () => {
   230→      cancelled = true;
   231→      task.cancel();
   232→    };
   233→  }, [getExtractData, getTransactionsData]);
   234→
   235→  const getActiveFiltersCount = useMemo(() => {
   236→    let count = 0;
   237→    if (appliedTransactionsFilters?.period !== undefined && appliedTransactionsFilters?.period !== null) count++;
   238→    if (appliedTransactionsFilters?.types?.length) count++;
   239→    return count > 0 ? count.toString() : undefined;
   240→  }, [appliedTransactionsFilters]);
   241→
   242→  const getTransactionsEmptyMessage = useMemo(() => {
   243→    const hasSearchText = debouncedSearchText && debouncedSearchText.trim() !== '';
   244→    const hasActiveFilters =
   245→      (appliedTransactionsFilters?.period !== undefined && appliedTransactionsFilters?.period !== null) ||
   246→      (appliedTransactionsFilters?.types?.length ?? 0) > 0;
   247→    return hasSearchText || hasActiveFilters
   248→      ? SCREEN_STRINGS.EMPTY_SEARCH_RESULTS
   249→      : SCREEN_STRINGS.EMPTY_ALL_LIST;
   250→  }, [debouncedSearchText, appliedTransactionsFilters]);
   251→
   252→  const getShouldShowTransactionsList = isLoadingExtract || transactionsData.length > 0;
   253→
   254→  const canLoadMore = pointsExtract.extractData?.pagination && 
   255→    pointsExtract.extractData.pagination.page < pointsExtract.extractData.pagination.totalPages;
   256→
   257→  useEffect(() => {
   258→    canLoadMoreRef.current = !!canLoadMore;
   259→  }, [canLoadMore]);
   260→
   261→  useEffect(() => {
