import { Box, Text, TagLabel, Button, BackDropBottom, SeparatorHorizontal, CardActivity, DetailTransactionValue } from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import React, { FC } from 'react';
import { Linking } from 'react-native';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { formatToCurrency } from '../../utils/functions';
import { moment } from '../../services/moment';
import { eventSelectContent } from '~/constants/functions';
import { PointsDetailProps } from './Models';
import {
  getTransactionGainType,
  getTagSubType,
  getDetailScreenTitle,
  getVehicleInfo,
  getPurchaseTypeLabel,
  getOrigin,
  getFormattedPointsValue,
  getFormattedHighlightText,
} from './utils';

const PointsDetailView: FC<PointsDetailProps> = ({
  handleGoBack,
  transaction,
  modalizeRef,
  handleOpenReportProblem,
  handleCloseReportProblem,
}) => {
  const gainType = getTransactionGainType(transaction);
  const tagSubType = getTagSubType(transaction);
  const screenTitle = getDetailScreenTitle(gainType, transaction.type);
  const vehicleInfo = getVehicleInfo(transaction);
  const purchaseTypeLabel = getPurchaseTypeLabel(tagSubType);
  const origin = getOrigin(transaction);
  const formattedCurrencyValue = formatToCurrency(transaction.currencyValue);
  const formattedPointsValue = getFormattedPointsValue(transaction.amount, transaction.type);
  const cardTitle = transaction.description || '';
  const highlightText = getFormattedHighlightText(transaction.date, gainType, moment);

  const renderDivider = () => {
    return (
      <SeparatorHorizontal
        borderWidth="smaller"
        borderColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
        mt="xxxxs"
      />
    );
  };

  const renderTagContent = () => {
    const hasVehicleInfo = !!vehicleInfo && vehicleInfo !== '';
    const shouldShowOrigin = origin && !hasVehicleInfo;
    const hasPurchaseTypeLabel = !!purchaseTypeLabel && purchaseTypeLabel !== '';


    return (
      <>
        {renderDivider()}
        {shouldShowOrigin && (
          <>
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Origem
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {origin}
            </Text>
            {renderDivider()}
          </>
        )}
        {hasVehicleInfo && (
          <>
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Tag
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {vehicleInfo}
            </Text>
            {renderDivider()}
          </>
        )}

        {hasPurchaseTypeLabel && (
          <>
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs" mt="xxxxs">
              Tipo de compra
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {purchaseTypeLabel}
            </Text>
          </>
        )}
      </>
    );
  };

  return (
    <>
      <BasicScreen
        title={screenTitle}
        leftIconOnPress={handleGoBack}
        hasScroll
        errorButtonOnPress={() => { }}
      >
      <DetailTransactionValue
          icon={transaction.icon}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={(transaction.type === 'RECEIVED' || transaction.type === 'REFUNDED') ? 'PLUS_COLOR_02' : 'INTENSE_COLOR_05' as const}
        />

        <Box ml='smaller' mr='smaller' mt='xxxxs' flex={1}>

          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
          />

          <Box mt="xxxs" flex={1} width="100%">
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
              Valor
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {formattedCurrencyValue}
            </Text>

          {gainType === 'TAG' && renderTagContent()}
          </Box>


          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="secundaryLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>

      </BasicScreen>

      <BackDropBottom
        modalizeRef={modalizeRef as PropsModalizeRef}
      >
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text type="paragraphXXXL" color="BRAND_COMPLEMENT_01" mb="xs" align="center">
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
            }}
          />
          <Text type="paragraphXS" color="INTENSE_COLOR_04" mt='xxxxs'>
            *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das 9h às 17h.
          </Text>


        </Box>

        <Box align="center" width="100%" mt='xxxxs'>
          <Text type="linkMD" color="INTENSE_COLOR_05" onPress={handleCloseReportProblem} align="center">
            Fechar
          </Text>
        </Box>
      </BackDropBottom>
    </>
  );
};

export default PointsDetailView;

import {
  BackDropBottom,
  Box,
  Button,
  CardActivity,
  DetailTransactionValue,
  SeparatorHorizontal,
  TagLabel,
  Text,
} from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import React, { FC } from 'react';
import { Linking } from 'react-native';
import { eventSelectContent } from '~/constants/functions';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { moment } from '../../services/moment';
import { formatToCurrency } from '../../utils/functions';
import { PointsDetailProps } from './Models';
import {
  getDetailScreenTitle,
  getFormattedHighlightText,
  getFormattedPointsValue,
  getOrigin,
  getPurchaseTypeLabel,
  getTagSubType,
  getTransactionGainType,
  getVehicleInfo,
} from './utils';

const PointsDetailView: FC<PointsDetailProps> = ({
  handleGoBack,
  transaction,
  modalizeRef,
  handleOpenReportProblem,
  handleCloseReportProblem,
}) => {
  const gainType = getTransactionGainType(transaction);
  const tagSubType = getTagSubType(transaction);
  const screenTitle = getDetailScreenTitle(gainType, transaction.type);
  const vehicleInfo = getVehicleInfo(transaction);
  const purchaseTypeLabel = getPurchaseTypeLabel(tagSubType);
  const origin = getOrigin(transaction);
  const formattedCurrencyValue = formatToCurrency(transaction.currencyValue);
  const formattedPointsValue = getFormattedPointsValue(
    transaction.amount,
    transaction.type,
  );
  const cardTitle = transaction.description || '';
  const highlightText = getFormattedHighlightText(
    transaction.date,
    gainType,
    moment,
  );

  const renderDivider = () => {
    return (
      <SeparatorHorizontal
        borderWidth="smaller"
        borderColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
        mt="xxxxs"
      />
    );
  };

  const renderTagContent = () => {
    const hasVehicleInfo = !!vehicleInfo && vehicleInfo !== '';
    const shouldShowOrigin = origin && !hasVehicleInfo;
    const hasPurchaseTypeLabel =
      !!purchaseTypeLabel && purchaseTypeLabel !== '';

    return (
      <>
        {renderDivider()}
        {shouldShowOrigin && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Origem
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {origin}
            </Text>
            {renderDivider()}
          </>
        )}
        {hasVehicleInfo && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Tag
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {vehicleInfo}
            </Text>
            {renderDivider()}
          </>
        )}

        {hasPurchaseTypeLabel && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Tipo de compra
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {purchaseTypeLabel}
            </Text>
          </>
        )}
      </>
    );
  };

  return (
    <>
      <BasicScreen
        title={screenTitle}
        leftIconOnPress={handleGoBack}
        hasScroll
        errorButtonOnPress={() => {}}
      >
        <DetailTransactionValue
          icon={transaction.icon as never}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={
            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
              ? 'PLUS_COLOR_02'
              : ('INTENSE_COLOR_05' as const)
          }
        />

        <Box ml="smaller" mr="smaller" mt="xxxxs" flex={1}>
          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
          />

          <Box mt="xxxs" flex={1} width="100%">
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
              Valor
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {formattedCurrencyValue}
            </Text>

            {gainType === 'TAG' && renderTagContent()}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="secundaryLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>
      </BasicScreen>

      <BackDropBottom modalizeRef={modalizeRef as PropsModalizeRef}>
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text
              type="paragraphXXXL"
              color="BRAND_COMPLEMENT_01"
              mb="xs"
              align="center"
            >
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
